    case .nullable(let count, let status, let config, let samples):
      w.bytes.append(UInt8(3))
      w.writeBool(count != nil); if let value = count { w.writeInt(value) }
      w.writeBool(status != nil); if let value = status { w.writeInt(value.rawValue) }
      w.writeBool(config != nil); if let value = config { value.writeFields(w) }
      w.writeBool(samples != nil); if let value = samples { w.writeInt32(Int32(value.count)); value.forEach { w.writeInt($0) } }
    }
  }

  public func toNative() -> UnsafeMutablePointer<UInt8>? {
    let writer = NitroRecordWriter()
    writeFields(to: writer)
    return writer.toNative()
  }
}

// Binary map encode/decode — [4B payload_len][4B count][entries: [4B kLen][kBytes][1B tag][vBytes]]
// Type tags: 1=int64, 2=float64, 3=bool, 4=string, 5=binary record/variant blob
private func _nitroEncodeMapBinary(_ m: [String: Any]) -> UnsafeMutablePointer<UInt8>? {
    var payload = Data()
    func writeLE32(_ v: Int32) { var lv = v.littleEndian; payload.append(contentsOf: withUnsafeBytes(of: &lv) { Data($0) }) }
    func writeLE64(_ v: Int64) { var lv = v.littleEndian; payload.append(contentsOf: withUnsafeBytes(of: &lv) { Data($0) }) }
    writeLE32(Int32(m.count))
    for (k, v) in m {
        let kb = k.data(using: .utf8)!; writeLE32(Int32(kb.count)); payload.append(kb)
        if let iv = v as? Int64 { payload.append(1); writeLE64(iv) }
        else if let dv = v as? Double { payload.append(2); writeLE64(Int64(bitPattern: dv.bitPattern)) }
        else if let bv = v as? Bool { payload.append(3); payload.append(bv ? 1 : 0) }
        else if let blob = v as? Data { payload.append(5); writeLE32(Int32(blob.count)); payload.append(blob) }
        else { let sv = "\(v)".data(using: .utf8)!; payload.append(4); writeLE32(Int32(sv.count)); payload.append(sv) }
    }
    var lenLE = Int32(payload.count).littleEndian
    let total = 4 + payload.count
    guard let buf = malloc(total) else { return nil }
    withUnsafeBytes(of: &lenLE) { memcpy(buf, $0.baseAddress!, 4) }
    payload.withUnsafeBytes { memcpy(buf.advanced(by: 4), $0.baseAddress!, payload.count) }
    return buf.assumingMemoryBound(to: UInt8.self)
}
private func _nitroDecodeMapBinary(_ ptr: UnsafeMutablePointer<UInt8>) -> [String: Any] {
    let payLen = Int(UnsafeRawPointer(ptr).loadUnaligned(as: UInt32.self).littleEndian)
    let data = Data(bytes: ptr.advanced(by: 4), count: payLen)
    var pos = 0
    func readLE32() -> Int { let v = data[pos..<(pos+4)].withUnsafeBytes { Int($0.loadUnaligned(as: UInt32.self).littleEndian) }; pos += 4; return v }
    func readLE64() -> Int64 { let v = data[pos..<(pos+8)].withUnsafeBytes { Int64(bitPattern: $0.loadUnaligned(as: UInt64.self).littleEndian) }; pos += 8; return v }
    let count = readLE32(); var result = [String: Any]()
    for _ in 0..<count {
        let kLen = readLE32(); let k = String(data: data[pos..<(pos+kLen)], encoding: .utf8)!; pos += kLen
        let tag = data[pos]; pos += 1
        switch tag {
        case 1: result[k] = readLE64()
        case 2: result[k] = Double(bitPattern: UInt64(bitPattern: readLE64()))
        case 3: result[k] = data[pos] != 0; pos += 1
        case 5: let bLen = readLE32(); result[k] = Data(data[pos..<(pos+bLen)]); pos += bLen
        default: let vLen = readLE32(); result[k] = String(data: data[pos..<(pos+vLen)], encoding: .utf8); pos += vLen
        }
    }
    return result
}

private func _nitroCopyTypedDataReturn(_ bytes: UnsafeRawBufferPointer) -> UnsafeMutablePointer<UInt8>? {
    let headerSize = MemoryLayout<Int64>.size
    let byteLength = bytes.count
    guard let raw = malloc(byteLength + headerSize) else { return nil }
    raw.storeBytes(of: Int64(byteLength), as: Int64.self)
    if let base = bytes.baseAddress, byteLength > 0 {
        memcpy(raw.advanced(by: headerSize), base, byteLength)
    }
    return raw.bindMemory(to: UInt8.self, capacity: byteLength + headerSize)
}

private func _nitroCopyTypedDataArrayReturn<T>(_ values: [T]) -> UnsafeMutablePointer<UInt8>? {
    return values.withUnsafeBufferPointer { buffer in
        _nitroCopyTypedDataReturn(UnsafeRawBufferPointer(buffer))
    }
}

private func _nitroMakeZeroCopyTypedDataReturn(_ bytes: UnsafeRawBufferPointer) -> UnsafeMutablePointer<UInt8>? {
    let headerSize = MemoryLayout<Int64>.size * 3
    let byteLength = bytes.count
    guard let raw = malloc(byteLength + headerSize) else { return nil }
    raw.storeBytes(of: Int64(byteLength), as: Int64.self)
    let payload = raw.advanced(by: headerSize)
    raw.advanced(by: MemoryLayout<Int64>.size).storeBytes(of: Int64(Int(bitPattern: payload)), as: Int64.self)
    raw.advanced(by: MemoryLayout<Int64>.size * 2).storeBytes(of: Int64(0), as: Int64.self)
    if let base = bytes.baseAddress, byteLength > 0 {
        memcpy(payload, base, byteLength)
    }
    return raw.bindMemory(to: UInt8.self, capacity: byteLength + headerSize)
}

private func _nitroMakeZeroCopyTypedDataArrayReturn<T>(_ values: [T]) -> UnsafeMutablePointer<UInt8>? {
    return values.withUnsafeBufferPointer { buffer in
        _nitroMakeZeroCopyTypedDataReturn(UnsafeRawBufferPointer(buffer))
    }
}

// MARK: - @NitroResult encoding helpers

private func _nitroWriteResultTag(_ tag: UInt8, _ payload: UnsafeMutablePointer<UInt8>?, _ payloadLen: Int) -> UnsafeMutablePointer<UInt8>? {
    let total = 1 + payloadLen
    guard let buf = UnsafeMutablePointer<UInt8>.allocate(capacity: total) as UnsafeMutablePointer<UInt8>? else { return nil }
    buf[0] = tag
    if payloadLen > 0, let payload = payload {
        buf.advanced(by: 1).initialize(from: payload, count: payloadLen)
    }
    return buf
}

private func _nitroEncodeResultInt64(_ v: Int64) -> UnsafeMutablePointer<UInt8>? {
    let w = NitroRecordWriter()
    w.writeInt(v)
    guard let payload = w.toNative() else { return _nitroWriteResultTag(0, nil, 0) }
    let payloadLen = 4 + Int(payload.pointee)  // 4B prefix + payload bytes
    return _nitroWriteResultTag(0, payload, payloadLen)
}

// Overload for plain Int (non-nullable) convenience
private func _nitroEncodeResultInt64(_ v: Int) -> UnsafeMutablePointer<UInt8>? {
    return _nitroEncodeResultInt64(Int64(v))
}

private func _nitroEncodeResultFloat64(_ v: Double) -> UnsafeMutablePointer<UInt8>? {
    let w = NitroRecordWriter()
    w.writeDouble(v)
    guard let payload = w.toNative() else { return _nitroWriteResultTag(0, nil, 0) }
    let payloadLen = 4 + Int(payload.pointee)
    return _nitroWriteResultTag(0, payload, payloadLen)
}

private func _nitroEncodeResultBool(_ v: Bool) -> UnsafeMutablePointer<UInt8>? {
    let w = NitroRecordWriter()
    w.writeBool(v)
    guard let payload = w.toNative() else { return _nitroWriteResultTag(0, nil, 0) }
    let payloadLen = 4 + Int(payload.pointee)
    return _nitroWriteResultTag(0, payload, payloadLen)
}

private func _nitroEncodeResultString(_ v: String) -> UnsafeMutablePointer<UInt8>? {
    let w = NitroRecordWriter()
    w.writeString(v)
    guard let payload = w.toNative() else { return _nitroWriteResultTag(0, nil, 0) }
    let payloadLen = 4 + Int(payload.pointee)
    return _nitroWriteResultTag(0, payload, payloadLen)
}

// For @HybridRecord / @NitroVariant result types — encode via toNative()/writeFields
private func _nitroEncodeResultRecord<T: NitroEncodable>(_ v: T) -> UnsafeMutablePointer<UInt8>? {
    guard let payload = v.toNative() else { return _nitroWriteResultTag(0, nil, 0) }
    let payloadLen = 4 + Int(payload.pointee)
    return _nitroWriteResultTag(0, payload, payloadLen)
}

private func _nitroEncodeResultError(_ error: Error) -> UnsafeMutablePointer<UInt8>? {
    let msg = error.localizedDescription
    let w = NitroRecordWriter()
    w.writeString(msg)
    guard let payload = w.toNative() else { return _nitroWriteResultTag(1, nil, 0) }
    let payloadLen = 4 + Int(payload.pointee)
    return _nitroWriteResultTag(1, payload, payloadLen)
}

